#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;
    long long ans=0;
    scanf("%d",&t);
    while(t--){
        string tp,val;
        cin>>tp;
        if(tp=="String"){
            cin>>val;
            long long sum=0;
            for(int i=0;i<val.size();i++){
                if(val[i]=='"'){
                    sum++;
                }else if(sum%2==1)
                    ans++;
            }
        }else if(tp=="int"){
            cin>>val;
            ans+=4;
            for(int i=0;i<val.size();i++)
                if(val[i]==',')
                    ans+=4;
        }else if(tp=="long"){
            cin>>val;
            ans+=8;
            for(int i=0;i<val.size();i++)
                if(val[i]==',')
                    ans+=8;
        }else if(tp=="int[]"){
            while(cin>>val){
                long long sum=0;
                if(val[0]=='i')
                    for(int i=4;val[i]>='0' && val[i]<='9';i++)
                        sum=sum*10+val[i]-'0';
                ans+=sum*4;
                if(val[val.size()-1]==';')
                    break;
            }
        }else if(tp=="long[]"){
            while(cin>>val){
                long long sum=0;
                if(val[0]=='l')
                    for(int i=5;val[i]>='0' && val[i]<='9';i++)
                        sum=sum*10+val[i]-'0';
                ans+=sum*8;
                if(val[val.size()-1]==';')
                    break;
            }
        }
    }
    if(ans/(1<<30))
        printf("%lldGB",ans/(1<<30));
    if((ans%(1<<30))/(1<<20))
        printf("%lldMB",(ans%(1<<30))/(1<<20));
    if((ans%(1<<20))/(1<<10))
        printf("%lldKB",(ans%(1<<20))/(1<<10));
    if(ans%(1<<10))
        printf("%lldB",ans%(1<<10));
    return 0;
}
